// T069: Query n8n execution history API for LinkedIn activity summary
// Filters by date range and workflow IDs (action_types) from request
// Uses N8N_API_KEY environment variable

const body = $input.all()[0].json.body;
const dateFrom = body?.date_from || new Date(Date.now() - 7 * 86400000).toISOString();
const dateTo = body?.date_to || new Date().toISOString();
const actionTypes = body?.action_types || ['linkedin-post', 'linkedin-comment', 'linkedin-like', 'feed-discovery'];

const apiKey = $env.N8N_API_KEY;

const summary = {
  posts: 0,
  comments: 0,
  likes: 0,
  feed_discoveries: 0
};

const details = [];

const workflowMapping = {
  'linkedin-post': 'posts',
  'linkedin-comment': 'comments',
  'linkedin-like': 'likes',
  'feed-discovery': 'feed_discoveries'
};

for (const actionType of actionTypes) {
  const summaryKey = workflowMapping[actionType];
  if (!summaryKey) continue;

  try {
    const url = `http://localhost:5678/api/v1/executions?status=success&workflowId=${actionType}&startedAfter=${encodeURIComponent(dateFrom)}&startedBefore=${encodeURIComponent(dateTo)}&limit=200`;

    if (!apiKey) {
      // No API key: return zeroes
      continue;
    }

    const response = await fetch(url, {
      headers: { 'X-N8N-API-KEY': apiKey }
    });

    if (response.ok) {
      const data = await response.json();
      const executions = data.data || [];
      summary[summaryKey] = executions.length;

      for (const exec of executions) {
        details.push({
          action_type: actionType,
          execution_id: exec.id,
          started_at: exec.startedAt,
          finished_at: exec.stoppedAt,
          status: exec.finished ? 'success' : 'running'
        });
      }
    }
  } catch (e) {
    // API may not be reachable; continue with zeroes
  }
}

// Sort details by started_at descending
details.sort((a, b) => new Date(b.started_at) - new Date(a.started_at));

return [{
  json: {
    status: 'ok',
    date_from: dateFrom,
    date_to: dateTo,
    summary: summary,
    details: details
  }
}];
